<template><view class="page"><xy-header title="钓虾生活馆" variant="brand" :show-back="false"/><view class="hero"><text class="title">轻松预约，快乐钓虾</text><text>{{me.card?`会员有效至 ${me.card.expireDate}`:'开通会员后即可预约座位'}}</text><button @click="go(me.card?'/pages/reserve/reserve':'/pages/membership/join')">{{me.card?'立即预约':'开通会员'}}</button></view><view class="grid"><view v-for="item in entries" :key="item.url" @click="go(item.url)"><text>{{item.label}}</text></view></view><view class="xy-tabbar-hold"></view><xy-tabbar active="index"/></view></template>
<script>import{appRequest,ensureMemberSession}from'../../utils/api';export default{data(){return{me:{},entries:[{label:'预约座位',url:'/pages/reserve/reserve'},{label:'我的预约',url:'/pages/reserve/history'},{label:'商城',url:'/pages/mall/mall'},{label:'我的订单',url:'/pages/order/list'},{label:'会员卡',url:'/pages/membership/card'},{label:'门店信息',url:'/pages/store/store'}]}},onShow(){this.load()},methods:{async load(){try{await ensureMemberSession();this.me=await appRequest({url:'/app/me'})}catch(e){}},go(url){if(url==='/pages/reserve/reserve'||url==='/pages/mall/mall')uni.reLaunch({url});else uni.navigateTo({url})}}}</script><style scoped>.page{min-height:100vh;background:var(--xy-bg)}.hero{display:flex;flex-direction:column;gap:22rpx;padding:50rpx 32rpx;color:#fff;background:linear-gradient(135deg,#0e9c8e,#0c6c88)}.title{font-size:42rpx;font-weight:800}.hero button{margin:10rpx 0 0;background:#fff;color:var(--xy-primary)}.grid{display:grid;grid-template-columns:repeat(2,1fr);gap:20rpx;padding:28rpx}.grid view{padding:38rpx 24rpx;border-radius:22rpx;background:#fff;box-shadow:var(--xy-shadow);font-weight:700}</style>
